import java.sql.*;

public class SecureSQLQuery {
    public static void main(String[] args) {
        try {
            // Simulating user input (which was vulnerable to SQL Injection)
            String userInput = "'; DROP TABLE users; --";

            // Establishing a connection to a SQLite database
            Connection conn = DriverManager.getConnection("jdbc:sqlite:test.db");

            // Creating a prepared statement with parameterized query
            String sql = "SELECT * FROM users WHERE username = ?";
            PreparedStatement pstmt = conn.prepareStatement(sql);

            // Setting the user input as a parameter in the prepared statement
            pstmt.setString(1, userInput);

            ResultSet rs = pstmt.executeQuery();

            while (rs.next()) {
                System.out.println("User found: " + rs.getString("username"));
            }

            conn.close();
        } catch (SQLException e) {
            System.err.println("SQL Exception: " + e.getMessage());
        }
    }
}
